mapper.select:
SELECT id, student_id, password, real_name, college_id, class_id, status, create_time, update_time
FROM sys_user
WHERE student_id = #{username}

SELECT id, student_id, password, real_name, college_id, class_id, status, create_time, update_time
FROM sys_user
WHERE id = #{id}

SELECT u.id AS userId, u.student_id AS userNo, u.real_name AS userName, u.college_id AS collegeId, u.class_id AS classId, u.status, u.create_time AS createTime, u.update_time AS updateTime FROM sys_user u INNER JOIN sys_user_role ur ON u.id = ur.user_id AND ur.role_id = #{studentRoleId}
AND u.student_id LIKE CONCAT('%', #{studentId}, '%')
AND u.status = #{status}
ORDER BY u.id DESC

mapper.update:
UPDATE sys_user
student_id = #{studentId}, password = #{password}, real_name = #{realName}, college_id = #{collegeId}, class_id = #{classId}, status = #{status},
WHERE id = #{id}
